INSERT INTO "ec_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content") VALUES ('01KNAGJYJD1RZAJRZX0KZ57Y8E','home','published',NULL,NULL,'2026-04-03T20:29:37.742Z','2026-04-08T17:14:44.110Z','2026-04-03T20:29:37.740Z',NULL,NULL,2,NULL,NULL,'en','01KNAGJYJD1RZAJRZX0KZ57Y8E','Home','[{"_type":"marketing.hero","_key":"hero","headline":"Handmade Italian in the heart of Austin","subheadline":"Taste the flour dust on fresh tagliatelle. Smell the wood smoke curling off a 900°F oven. Feel the warmth of family-style dining. Bella''s brings the quiet intensity of Italian nonna cooking to South Congress — where every plate tells the story of real ingredients, real technique, and the kind of care you taste in every bite.","primaryCta":{"label":"Reserve a Table","url":"/contact"},"secondaryCta":{"label":"See the Menu","url":"/pricing"}},{"_type":"marketing.features","_key":"features","headline":"Why people love Bella''s","subheadline":"Simple ingredients. Real technique. Every dish made with intention.","features":[{"icon":"zap","title":"Fresh Pasta Daily","description":"Every morning, you can taste the warmth of freshly made dough. We roll and cut by hand — tagliatelle, pappardelle, ravioli with delicate fillings. The pasta dries for just hours, then hits your plate before noon. That tender bite is what we''re after."},{"icon":"shield","title":"Wood-Fired Pizza","description":"Our imported Stefano Ferrara oven roars at 900°F, turning out Neapolitan pizzas in 60 seconds. The char, the stretch, the smoke — that''s the wood-fire magic. Order one and watch the blister bloom across the crust."},{"icon":"users","title":"Family Style Available","description":"Hosting a group? We do family-style right — platters passed hand to hand, everyone sharing from the same dishes. It''s how Italians eat. Just show up hungry and bring people you like talking to."},{"icon":"chart","title":"Curated Wine List","description":"Over 40 Italian wines by the bottle — all chosen by our sommelier with one rule: drink what you want to drink. Every Tuesday, he picks a new ''wine of the week'' that pairs gorgeously with whatever''s on the specials board. He''ll talk your ear off about terroir if you let him."},{"icon":"code","title":"Private Events","description":"Our back room is intimate — exposed brick, warm lighting, seats 24. Birthdays feel special here. Rehearsal dinners feel like celebrations. Even corporate dinners turn into conversations over wine and time."},{"icon":"globe","title":"Seasonal Specials","description":"The menu follows the season — peaches in summer, mushrooms in fall, citrus in winter. Every Tuesday morning, we hit the farmers market. Whatever''s at peak ripeness becomes the specials board. That''s where the magic lives."}]},{"_type":"marketing.testimonials","_key":"testimonials","headline":"What our guests say","testimonials":[{"quote":"I drove from San Antonio just for the cacio e pepe. Four cheeses, cracked pepper, and pasta water — simple, but something transcendent happens when they come together. This is the real deal. Worth every mile.","author":"James K.","role":"Google Review","company":"5 stars"},{"quote":"We''ve had our anniversary dinner here three years running. The osso buco — falling off the bone, swimming in that deep brown ragù, with the bright citrus of gremolata — somehow tastes better each time. It''s become our tradition.","author":"Maria & Tony R.","role":"Yelp Review","company":"5 stars"},{"quote":"Best Italian in Austin, hands down. The burrata appetizer — that creamy, almost molten center with the stretchy mozzarella shell — over heirloom tomatoes the color of sunset. It shouldn''t be complicated, but somehow it''s unforgettable.","author":"Priya S.","role":"Google Review","company":"5 stars"}]},{"_type":"marketing.faq","_key":"faq","headline":"Good to know","items":[{"question":"Do you take reservations?","answer":"Yes! Book a table for Friday and Saturday evenings — those nights fill up fast. We love walk-ins Tuesday through Thursday, and Sunday brunch is mostly first-come, first-served. Reserve online or call (512) 555-0142. Our host will greet you by name."},{"question":"Do you accommodate dietary restrictions?","answer":"Absolutely. We make gluten-free pasta in-house — same care, same technique. Many dishes are naturally vegetarian too. Tell your server about allergies before you sit down. Our kitchen takes them seriously. We''d rather remake something than rush it."},{"question":"Is there parking?","answer":"We have a small lot behind the restaurant — enter from 3rd Street. Street parking is easy along South Congress too. On Friday and Saturday evenings, we offer valet so you can walk in with your hands free and your appetite ready."},{"question":"Do you cater?","answer":"Yes — we do catering for groups of 20 or more. We bring the wood-fired energy to your event. Email catering@bellasbistro.com with your date and guest count, and we''ll build a menu that feels like Bella''s — handmade, seasonal, unforgettable."}]}]');
INSERT INTO "ec_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content") VALUES ('01KNAGJYJK07F4MW2QAAP0DE5K','pricing','published',NULL,NULL,'2026-04-03T20:29:37.747Z','2026-04-08T17:14:44.117Z','2026-04-03T20:29:37.747Z',NULL,NULL,2,NULL,NULL,'en','01KNAGJYJK07F4MW2QAAP0DE5K','Menu','[{"_type":"marketing.hero","_key":"menu-hero","headline":"Our Menu","subheadline":"Chef Marco believes in three things: ingredients you can trust, technique that honors them, and the kind of time a dish deserves. Nothing is rushed. Nothing is precious. Everything is made with the quiet intensity of someone who learned to cook in their grandmother''s kitchen. This is what that looks like.","centered":true},{"_type":"marketing.pricing","_key":"menu-sections","plans":[{"name":"Antipasti","price":"$12–$18","description":"Begin the night with something beautiful — fresh, bright, unexpected.","features":["Burrata with heirloom tomatoes & basil oil — the center still creamy at room temperature","Wood-fired octopus with lemon, capers & peperoncini — charred and impossibly tender","Prosciutto San Daniele & fig jam crostini with aged balsamic","Seasonal soup (ask your server — changes daily with market finds)","Arancini — saffron risotto fried golden, filled with ragù & fresh peas, served hot with warm marinara for dipping"],"cta":{"label":"Reserve a Table","url":"/contact"}},{"name":"Pasta & Entrées","price":"$22–$38","description":"Our pasta is rolled by hand. Our sauces are built over hours. This is where technique becomes art.","features":["Cacio e pepe — our signature dish. Pecorino Romano, cracked black pepper, fresh egg pasta. Simple. Perfect.","Pappardelle with wild boar ragù — braised for 4 hours until it darkens and deepens. Served with a whisper of Pecorino","Lobster ravioli in saffron cream with crispy sage — delicate pasta folded around sweet Maine lobster","Osso buco with gremolata — veal shank braised until the marrow begs to be eaten. Bright citrus zest brings it all alive","Branzino al forno — whole Mediterranean sea bass roasted until skin crackles, served with lemon & wild herbs","12oz Bistecca alla Fiorentina — dry-aged Florentine steak, grilled on high heat, finished with fleur de sel & olive oil","Eggplant parmigiana — layered eggplant, fresh mozzarella, basil, and tomato sauce, baked until bubbling and golden"],"cta":{"label":"Reserve a Table","url":"/contact"},"highlighted":true},{"name":"Dolci","price":"$10–$14","description":"Finish the way the Italians do — with something sweet, something small, something you''ll remember.","features":["Classic tiramisu — mascarpone, espresso, cocoa. Made fresh each morning","Panna cotta with seasonal fruit — silky cream wobbling on your spoon, topped with what''s at peak ripeness","Affogato — hot espresso poured over cold vanilla gelato. Simple chemistry. Pure joy.","Cannoli (filled to order) — crispy shell, creamy ricotta filling with dark chocolate chips. Nonna''s recipe","Chocolate torta — dark chocolate, ground almonds, a whisper of grappa. Served at room temperature"],"cta":{"label":"See Wine List","url":"/contact"}}]},{"_type":"marketing.faq","_key":"menu-faq","headline":"Menu notes","items":[{"question":"Does the menu change?","answer":"Our core pasta and pizza menu stays steady. But the specials board? That changes weekly. Every Tuesday morning, we load up at the farmers market and whatever is singing gets added to our menu. That''s the best meal you''ll have here — something seasonal, something unexpected."},{"question":"Can you accommodate large groups?","answer":"Yes — for groups of 8 or more, we offer a family-style prix fixe at $55 per person (or $75 with wine pairings). You get: a shared antipasti board, two pasta courses, your choice of an entrée, family-style sides, and dessert. No decisions to make. Just show up hungry."},{"question":"Do you have a kids menu?","answer":"We do. Kid portions of our pasta dishes run $12 — real food, smaller plates. And yes, we have buttered noodles for the pickier diners. But honestly, kids love the pizza. A lot of them end up ordering off the regular menu and polishing their plates."}]}]');
INSERT INTO "ec_pages" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","content") VALUES ('01KNAGJYJSEZ6NANQHTZ962D9Y','contact','published',NULL,NULL,'2026-04-03T20:29:37.753Z','2026-04-08T17:14:44.119Z','2026-04-03T20:29:37.753Z',NULL,NULL,2,NULL,NULL,'en','01KNAGJYJSEZ6NANQHTZ962D9Y','Reserve a Table','[{"_type":"marketing.hero","_key":"contact-hero","headline":"Reserve a table","subheadline":"Walk-ins welcome Tuesday–Thursday. Reservations recommended for Friday, Saturday, and Sunday brunch. Call (512) 555-0142 or book below.","centered":true}]');
